#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char S[100005]; scanf("%s", S);
        int bal = 0; int ok = 1;
        for (int i = N-1; i >= 0; --i) {
            bal += (S[i] == '1') ? 1 : -1;
            if (bal < -1 || bal > 1) { ok = 0; break; }
        }
        puts(ok ? "YES" : "NO");
    }
    return 0;
}

