#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        S = next(it)
        bal = 0
        ok = True
        for ch in reversed(S):
            bal += 1 if ch == '1' else -1
            if bal < -1 or bal > 1:
                ok = False
                break
        out.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

